import { Checkbox, InputGroup } from "@chakra-ui/react";
import { FinancialAccessibilityGrade } from "../../../../generated/graphql";
import { useFilter } from "@/filters/providers/FilterProvider";
import { FiltersType } from "@/filters/types";
const FreeOrPaysYouFilter = () => {
  const {
    editedFilters,
    onAdd,
    onRemove
  } = useFilter();
  const handleChange = (checked: boolean) => {
    if (checked) {
      onAdd(FiltersType.FINANCIAL_ACCESSIBILITY, FinancialAccessibilityGrade.APlus);
      onAdd(FiltersType.FINANCIAL_ACCESSIBILITY, FinancialAccessibilityGrade.A);
    } else {
      onRemove(FiltersType.FINANCIAL_ACCESSIBILITY, FinancialAccessibilityGrade.APlus);
      onRemove(FiltersType.FINANCIAL_ACCESSIBILITY, FinancialAccessibilityGrade.A);
    }
  };
  const selectedFinancialAccessibilityGrades = editedFilters[FiltersType.FINANCIAL_ACCESSIBILITY] ?? [];
  const isChecked = selectedFinancialAccessibilityGrades.includes(FinancialAccessibilityGrade.APlus) && selectedFinancialAccessibilityGrades.includes(FinancialAccessibilityGrade.A);
  return <InputGroup mb={2} data-sentry-element="InputGroup" data-sentry-component="FreeOrPaysYouFilter" data-sentry-source-file="FreeOrPaysYouFilter.tsx">
      <Checkbox iconSize="10px" variant="snowday" isChecked={isChecked} onChange={e => handleChange(e.target.checked)} data-sentry-element="Checkbox" data-sentry-source-file="FreeOrPaysYouFilter.tsx" />
    </InputGroup>;
};
export default FreeOrPaysYouFilter;