import { Box, Flex, HStack } from "@chakra-ui/react";
import { useRouter } from "next/router";
import { useEffect } from "react";
import SearchInput from "./components/SearchInput";
import { SearchResults } from "./components/SearchResults";
import { useSearch } from "./providers/SearchProvider";
import { EmbeddedFilters } from "../filters/components/EmbeddedFilters";
import { SnowdayHead } from "../seo/components/SnowdayHead";
import { TopSearches } from "@/search/components/topSearch/TopSearches";
import { useIsExtraLargeScreen } from "@/ui/hooks/useIsExtraLargeScreen";
export default function SearchScreen() {
  const router = useRouter();
  const {
    query
  } = useSearch();
  const isExtraLargeScreen = useIsExtraLargeScreen();
  useEffect(() => {
    if (query) {
      router.replace(`/search/results?query=${query}`, undefined, {
        shallow: true
      });
    }
  }, [query]);
  const handleGoBack = () => {
    router.back();
  };
  const renderContent = () => {
    if (router.route === "/search") {
      return <Box flexGrow={1} className="scrollbar" mt={12}>
          <TopSearches />
        </Box>;
    } else {
      return <Box width="100%">
          <HStack alignItems="flex-start" gap={10}>
            {isExtraLargeScreen ? <Box width="385px" flexBasis="385px" flexShrink={0}>
                <EmbeddedFilters />
              </Box> : null}
            <SearchResults />
          </HStack>
        </Box>;
    }
  };
  return <Flex flexDirection="column" data-sentry-element="Flex" data-sentry-component="SearchScreen" data-sentry-source-file="SearchScreen.tsx">
      <SnowdayHead title="Search Results | Snowday" description="Explore curated opportunities based on your filters." noIndex={true} data-sentry-element="SnowdayHead" data-sentry-source-file="SearchScreen.tsx" />
      <Box flexGrow={1} px={{
      base: 3,
      lg: 4
    }} data-sentry-element="Box" data-sentry-source-file="SearchScreen.tsx">
        <Box my={{
        base: 3,
        lg: 6
      }} data-sentry-element="Box" data-sentry-source-file="SearchScreen.tsx">
          <SearchInput goBack={true} onClick={handleGoBack} icon="ArrowLeft" data-sentry-element="SearchInput" data-sentry-source-file="SearchScreen.tsx" />
        </Box>
        {renderContent()}
      </Box>
    </Flex>;
}