import { useGetTagsAutoCompleteSearchQuery } from "@/generated/graphql"
import graphqlRequestClient from "@/graphql/client"
import useDebounce from "@/ui/hooks/useDebounce"

export const useTagsAutoCompleteSearch = (query?: string) => {
  const debouncedQuery = useDebounce(query, 300)

  const { data, isFetching } = useGetTagsAutoCompleteSearchQuery(
    graphqlRequestClient,
    {
      query: debouncedQuery?.toLowerCase(),
    },
    {
      enabled: debouncedQuery !== "",
      keepPreviousData: true,
    },
  )

  return {
    debouncedQuery,
    isFetching,
    tags: data?.tagsAutoCompleteSearch.map((tag) => tag.name) ?? [],
  }
}
