import { Box, Button } from "@chakra-ui/react";
import React from "react";
interface PaginationComponentProps {
  totalResults: number;
  pageNumber: number;
  pageSize: number;
  onChange?: (page: number) => void;
}
const PaginationComponent = ({
  totalResults,
  pageNumber,
  pageSize,
  onChange
}: PaginationComponentProps) => {
  const totalPages = Math.ceil(totalResults / pageSize);
  const pageNumbers = Array.from({
    length: totalPages
  }, (_, i) => i + 1);
  if (totalPages <= 1) {
    return null;
  }
  return <Box display="flex" justifyContent="center" alignItems="center" mt="4" flexWrap="wrap" data-sentry-element="Box" data-sentry-component="PaginationComponent" data-sentry-source-file="Pagination.tsx">
      {pageNumbers.map((number, i) => {
      const isActive = pageNumber === i;
      return <Button mx="1" key={number} onClick={() => onChange?.(i)} variant={isActive ? "solid" : "ghost"} colorScheme={isActive ? "blue" : "gray"}>
            {number}
          </Button>;
    })}
    </Box>;
};
export default PaginationComponent;