import { Box, Flex, Input, InputGroup, InputLeftElement, Tag as TagComponent, Text } from "@chakra-ui/react";
import HTMLReactParser from "html-react-parser";
import { useState } from "react";
import { useFilter } from "@/filters/providers/FilterProvider";
import { FiltersType } from "@/filters/types";
import SnowdayIcons from "@/icons/SnowdayIcons";
import { useTagsAutoCompleteSearch } from "@/search/hooks/useTagsAutoCompleteSearch";
import { makeBold } from "@/utils/index";
const TagsFilter = () => {
  const {
    editedFilters,
    onAdd,
    onRemove
  } = useFilter();
  const [query, setQuery] = useState<string>();
  const {
    tags
  } = useTagsAutoCompleteSearch(query);
  const [querying, setQuerying] = useState<boolean>(false);
  const handleAdd = (tag: string) => {
    onAdd(FiltersType.TAGS, tag);
    setQuery(undefined);
  };
  return <>
      <Box position="relative" data-sentry-element="Box" data-sentry-source-file="TagsFilter.tsx">
        <InputGroup bg="white" position="relative" mb={2} zIndex={8} onKeyDown={() => !querying && setQuerying(true)} onBlur={() => querying && setQuerying(false)} onClick={() => setQuerying(!querying)} data-sentry-element="InputGroup" data-sentry-source-file="TagsFilter.tsx">
          <InputLeftElement children={<SnowdayIcons name="Search" boxSize={6} />} data-sentry-element="InputLeftElement" data-sentry-source-file="TagsFilter.tsx" />
          <Input errorBorderColor="snow.errors" value={query} onChange={e => setQuery(e.target.value)} placeholder="Add more tags to filter on..." data-sentry-element="Input" data-sentry-source-file="TagsFilter.tsx" />
          <Flex display={querying && query !== "" ? "flex" : "none"} position="absolute" width="100%" bg="white" maxH="240px" overflowY="scroll" top={9} borderBottomRadius={8} boxShadow="0px 1px 2px rgba(52, 67, 114, 0.08), 0px 2px 4px rgba(52, 67, 114, 0.2)" flexDirection="column" zIndex={0} data-sentry-element="Flex" data-sentry-source-file="TagsFilter.tsx">
            {tags.map(tag => <Flex key={tag} py={3} pl={10} cursor="pointer" onMouseDown={e => e.preventDefault()} _hover={{
            textDecoration: "underline"
          }} onClick={() => handleAdd(tag)}>
                <Text>
                  {HTMLReactParser(query && tag ? makeBold(query, tag) : "")}
                </Text>
              </Flex>)}
          </Flex>
        </InputGroup>
        {editedFilters[FiltersType.TAGS] && Array.isArray(editedFilters[FiltersType.TAGS]) && <Flex gap={2}>
              {editedFilters[FiltersType.TAGS].map(tag => <TagComponent key={"tag-" + tag} rounded="full" px={{
          base: 3,
          md: 4
        }} py={1} color="snow.blue-dark">
                  {tag}
                  <SnowdayIcons name="CloseCircle" ml={2} cursor="pointer" color="snow.blue-dark" onClick={() => onRemove(FiltersType.TAGS, tag)} />
                </TagComponent>)}
            </Flex>}
      </Box>
    </>;
};
export default TagsFilter;