import { Checkbox, Flex, Text } from "@chakra-ui/react";
import { useFilter } from "@/filters/providers/FilterProvider";
import { RestrictionFiltersType } from "@/filters/types";
interface RestrictionFilter {
  label: string;
  filterKey: RestrictionFiltersType;
}
const RestrictionFilter = ({
  label,
  filterKey
}: RestrictionFilter) => {
  const {
    editedFilters,
    onUpdate
  } = useFilter();
  const handleChange = (checked: boolean) => {
    onUpdate(filterKey, checked);
  };
  return <Flex justifyContent="space-between" mb={-2} data-sentry-element="Flex" data-sentry-component="RestrictionFilter" data-sentry-source-file="RestrictionFilter.tsx">
      <Text flexGrow={1} data-sentry-element="Text" data-sentry-source-file="RestrictionFilter.tsx">{label}</Text>
      <Checkbox name={filterKey} iconSize="10px" variant="snowday" key={"checkbox-" + filterKey} value={filterKey} isChecked={editedFilters[filterKey] ?? false} onChange={e => handleChange(e.target.checked)} data-sentry-element="Checkbox" data-sentry-source-file="RestrictionFilter.tsx" />
    </Flex>;
};
export default RestrictionFilter;