import { Checkbox, IconProps, InputGroup, Stack } from "@chakra-ui/react";
import { ComponentType } from "react";
import { FiltersType } from "@/features/filters/types";
import { useFilter } from "@/filters/providers/FilterProvider";
import { ExpertsChoiceRating } from "@/generated/graphql";
import HighlyRecommendedIcon from "@/ui/icons/HighlyRecommended";
import MostRecommendedIcon from "@/ui/icons/MostRecommended";
const options: {
  label: string;
  Icon: ComponentType<IconProps>;
  value: ExpertsChoiceRating;
  size?: number;
  disabled?: boolean;
}[] = [{
  label: "Most",
  Icon: MostRecommendedIcon,
  value: ExpertsChoiceRating.MostRecommended,
  size: 5
}, {
  label: "Highly",
  Icon: HighlyRecommendedIcon,
  value: ExpertsChoiceRating.HighlyRecommended,
  size: 5
}];
const ExpertsChoiceFilter = () => {
  const {
    editedFilters,
    onToggle
  } = useFilter();
  const onChange = (value: ExpertsChoiceRating, _checked: boolean) => {
    onToggle(FiltersType.EXPERTS_CHOICE, value);
  };
  return <InputGroup mb={2} w="100%" data-sentry-element="InputGroup" data-sentry-component="ExpertsChoiceFilter" data-sentry-source-file="ExpertsChoiceFilter.tsx">
      <Stack direction="row" width="100%" gap={0} data-sentry-element="Stack" data-sentry-source-file="ExpertsChoiceFilter.tsx">
        {options.map(option => {
        const isChecked = editedFilters[FiltersType.EXPERTS_CHOICE]?.includes(option.value) ?? false;
        return <Checkbox key={`type-${option.value}`} variant="filterStack" value={option.value} disabled={option.disabled ?? false} onChange={e => onChange(option.value, e.target.checked)} isChecked={isChecked} textAlign="center">
              <option.Icon boxSize={option.size ?? 6} />
              <br />
              {option.label}
            </Checkbox>;
      })}
      </Stack>
    </InputGroup>;
};
export default ExpertsChoiceFilter;