import { Checkbox, InputGroup } from "@chakra-ui/react";
import { useFilter } from "@/filters/providers/FilterProvider";
import { FiltersType } from "@/filters/types";
const AllowsInternationalStudentsFilter = () => {
  const {
    editedFilters,
    onUpdate
  } = useFilter();
  const handleChange = (checked: boolean) => {
    onUpdate(FiltersType.ALLOWS_INTERNATIONAL_STUDENTS, checked);
  };
  return <InputGroup mb={2} data-sentry-element="InputGroup" data-sentry-component="AllowsInternationalStudentsFilter" data-sentry-source-file="AllowsInternationalStudentsFilter.tsx">
      <Checkbox iconSize="10px" variant="snowday" isChecked={editedFilters[FiltersType.ALLOWS_INTERNATIONAL_STUDENTS] ?? false} onChange={e => handleChange(e.target.checked)} data-sentry-element="Checkbox" data-sentry-source-file="AllowsInternationalStudentsFilter.tsx" />
    </InputGroup>;
};
export default AllowsInternationalStudentsFilter;