import { Checkbox, IconProps, InputGroup, Stack } from "@chakra-ui/react";
import { ComponentType } from "react";
import { FiltersType } from "@/features/filters/types";
import { useFilter } from "@/filters/providers/FilterProvider";
import { Season } from "@/generated/graphql";
import FallIcon from "@/ui/icons/Fall";
import SpringIcon from "@/ui/icons/Spring";
import SunIcon from "@/ui/icons/Sun";
const options: {
  label: string;
  Icon: ComponentType<IconProps>;
  value: Season;
  size?: number;
  disabled?: boolean;
}[] = [{
  label: "Summer",
  Icon: SunIcon,
  value: Season.Summer
}, {
  label: "Fall",
  Icon: FallIcon,
  value: Season.Fall,
  size: 5
}, {
  label: "Spring",
  Icon: SpringIcon,
  value: Season.Spring,
  size: 5
}];
const SeasonFilter = () => {
  const {
    editedFilters,
    onToggle
  } = useFilter();
  const onChange = (value: Season, _checked: boolean) => {
    onToggle(FiltersType.SEASON, value);
  };
  return <InputGroup mb={2} w="100%" data-sentry-element="InputGroup" data-sentry-component="SeasonFilter" data-sentry-source-file="SeasonFilter.tsx">
      <Stack direction="row" width="100%" gap={0} data-sentry-element="Stack" data-sentry-source-file="SeasonFilter.tsx">
        {options.map(option => {
        const isChecked = editedFilters[FiltersType.SEASON]?.includes(option.value) ?? false;
        return <Checkbox key={`type-${option.value}`} variant="filterStack" value={option.value} disabled={option.disabled ?? false} onChange={e => onChange(option.value, e.target.checked)} isChecked={isChecked} textAlign="center">
              <option.Icon boxSize={option.size ?? 6} />
              <br />
              {option.label}
            </Checkbox>;
      })}
      </Stack>
    </InputGroup>;
};
export default SeasonFilter;