import { Accordion, Box } from "@chakra-ui/react";
import { useEffect, useMemo, useState } from "react";
import FilterAccordionItem from "./FilterAccordionItem";
import FilterItem from "./FilterItem";
import { FinancialAccessibilityGrade } from "../../../generated/graphql";
import { featureFlags } from "../../featureFlags/utils";
import { useFilter } from "../providers/FilterProvider";
import { FilterCategoriesType, FiltersType } from "../types";
interface FilterItem {
  type: FiltersType;
  stack?: boolean;
}
interface Filter {
  name: string;
  type: FilterCategoriesType;
  items: FilterItem[];
}
const filterOptions: Filter[] = [{
  name: "Quick filters",
  type: FilterCategoriesType.QUICK_FILTERS,
  items: [{
    type: FiltersType.EXPERTS_CHOICE
  }, {
    type: FiltersType.TYPE
  }, {
    type: FiltersType.LOCATION
  }, {
    type: FiltersType.SEASON
  }, {
    type: FiltersType.GRADES
  }, {
    type: FiltersType.INTERESTS
  }, {
    type: FiltersType.TAGS
  }, {
    type: FiltersType.FINANCIAL_ACCESSIBILITY
  }]
}, {
  name: "Advanced Criteria",
  type: FilterCategoriesType.ADVANCED_CRITERIA,
  items: [{
    type: FiltersType.HIGHLY_SELECTIVE,
    stack: false
  }, {
    type: FiltersType.FREE_OR_PAYS_YOU,
    stack: false
  }, {
    type: FiltersType.ALLOWS_INTERNATIONAL_STUDENTS,
    stack: false
  }, {
    type: FiltersType.COLLEGE_CREDIT,
    stack: false
  }, {
    type: FiltersType.ONE_ON_ONE,
    stack: false
  }, {
    type: FiltersType.AVAILABILITY
  }, {
    type: FiltersType.DEADLINE
  }]
}, {
  name: "Only For...",
  type: FilterCategoriesType.ONLY_FOR,
  items: [{
    type: FiltersType.LOW_INCOME_ONLY
  }, {
    type: FiltersType.FIRST_GENERATION_ONLY
  }, {
    type: FiltersType.UNDER_REPRESENTED_MINORITIES_ONLY
  }, {
    type: FiltersType.GIRLS_ONLY
  }, {
    type: FiltersType.BOYS_ONLY
  }]
}, {
  name: "Filter Out Opportunities Only For...",
  type: FilterCategoriesType.FILTER_OUT_OPPORTUNITIES_ONLY_FOR,
  items: [{
    type: FiltersType.EXCLUDE_LOW_INCOME_ONLY
  }, {
    type: FiltersType.EXCLUDE_FIRST_GENERATION_ONLY
  }, {
    type: FiltersType.EXCLUDE_UNDER_REPRESENTED_MINORITIES_ONLY
  }, {
    type: FiltersType.EXCLUDE_GIRLS_ONLY
  }, {
    type: FiltersType.EXCLUDE_BOYS_ONLY
  }]
}];
export const Filters = () => {
  const {
    appliedFilters
  } = useFilter();
  const hasTagFilters = useMemo(() => {
    const appliedTagFilters = appliedFilters[FiltersType.TAGS];
    return appliedTagFilters !== undefined && Array.isArray(appliedTagFilters) && appliedTagFilters.length > 0;
  }, [appliedFilters]);
  const [enableTagFilters, setEnableTagFilters] = useState<boolean>(hasTagFilters);
  useEffect(() => {
    // Tag filters can be enabled, but never disabled, currently
    if (hasTagFilters) {
      setEnableTagFilters(hasTagFilters);
    }
  }, [hasTagFilters]);
  const isAdvancedCriteriaSectionExpanded = appliedFilters[FiltersType.HIGHLY_SELECTIVE] || appliedFilters[FiltersType.FINANCIAL_ACCESSIBILITY]?.includes(FinancialAccessibilityGrade.APlus) && appliedFilters[FiltersType.FINANCIAL_ACCESSIBILITY]?.includes(FinancialAccessibilityGrade.A) || appliedFilters[FiltersType.ALLOWS_INTERNATIONAL_STUDENTS] || appliedFilters[FiltersType.COLLEGE_CREDIT] || Array.isArray(appliedFilters[FiltersType.INTERESTS]) && appliedFilters[FiltersType.INTERESTS]?.some(interest => interest === "1-on-1") || !Array.isArray(appliedFilters[FiltersType.INTERESTS]) && appliedFilters[FiltersType.INTERESTS] === "1-on-1" || appliedFilters[FiltersType.AVAILABILITY] || appliedFilters[FiltersType.DEADLINE];
  const isOnlyForSectionExpanded = appliedFilters[FiltersType.LOW_INCOME_ONLY] || appliedFilters[FiltersType.FIRST_GENERATION_ONLY] || appliedFilters[FiltersType.UNDER_REPRESENTED_MINORITIES_ONLY] || appliedFilters[FiltersType.GIRLS_ONLY] || appliedFilters[FiltersType.BOYS_ONLY];
  const isFilterOutSectionExpanded = appliedFilters[FiltersType.EXCLUDE_LOW_INCOME_ONLY] || appliedFilters[FiltersType.EXCLUDE_FIRST_GENERATION_ONLY] || appliedFilters[FiltersType.EXCLUDE_UNDER_REPRESENTED_MINORITIES_ONLY] || appliedFilters[FiltersType.EXCLUDE_GIRLS_ONLY] || appliedFilters[FiltersType.EXCLUDE_BOYS_ONLY];
  const defaultIndex = useMemo(() => {
    const indices: number[] = [0]; // Always expand Quick Filters and Advanced Criteria

    if (isAdvancedCriteriaSectionExpanded) {
      indices.push(1);
    }
    if (isOnlyForSectionExpanded) {
      indices.push(2);
    }
    if (isFilterOutSectionExpanded) {
      indices.push(3);
    }
    return indices;
  }, [isAdvancedCriteriaSectionExpanded, isOnlyForSectionExpanded, isFilterOutSectionExpanded]);
  const [expandedIndices, setExpandedIndices] = useState<number[]>(defaultIndex);
  useEffect(() => setExpandedIndices(defaultIndex), [defaultIndex]);
  return <>
      <Box flexGrow={1} py={5} px={2} overflow="auto" data-sentry-element="Box" data-sentry-source-file="Filters.tsx">
        <Accordion allowMultiple={true} index={expandedIndices} onChange={nextIndex => setExpandedIndices(nextIndex as number[])} data-sentry-element="Accordion" data-sentry-source-file="Filters.tsx">
          {filterOptions.filter(({
          type
        }) => featureFlags[type]).map(filter => <FilterAccordionItem key={"filter-category-" + filter.name} name={filter.name}>
                {filter.items.filter(({
            type
          }) => {
            // Only display the Tags filter if there are already applied tag filters
            // E.g. From a pre-built URL. This is to avoid exposing tags to all users
            // before we have a large number of tags in the system.
            if (type === FiltersType.TAGS) {
              return enableTagFilters;
            }
            return featureFlags[type];
          }).map((item: FilterItem) => <FilterItem key={"filter-item-" + item.type} type={item.type} stack={item.stack} />)}
              </FilterAccordionItem>)}
        </Accordion>
      </Box>
    </>;
};