import { Checkbox, InputGroup } from "@chakra-ui/react";
import { useFilter } from "@/filters/providers/FilterProvider";
import { FiltersType } from "@/filters/types";
const SelectiveFilter = () => {
  const {
    editedFilters,
    onUpdate
  } = useFilter();
  const handleChange = (value: boolean) => {
    onUpdate(FiltersType.HIGHLY_SELECTIVE, value || undefined);
  };
  return <>
      <InputGroup mb={2} data-sentry-element="InputGroup" data-sentry-source-file="SelectiveFilter.tsx">
        <Checkbox iconSize="10px" variant="snowday" isChecked={editedFilters[FiltersType.HIGHLY_SELECTIVE] ?? false} onChange={e => handleChange(e.target.checked)} data-sentry-element="Checkbox" data-sentry-source-file="SelectiveFilter.tsx" />
      </InputGroup>
    </>;
};
export default SelectiveFilter;